package com.evolua.emotional.infrastructure.persistence; import jakarta.persistence.*; import java.time.Instant; @Entity @Table(name = "check_ins") public class CheckInEntity { @Id @GeneratedValue(strategy = GenerationType.IDENTITY) private Long id; private String userId; private String mood; private String reflection; private Integer energyLevel; private String recommendedPractice; private Instant createdAt; public Long getId() { return id; } public void setId(Long id) { this.id = id; } public String getUserId() { return userId; } public void setUserId(String userId) { this.userId = userId; } public String getMood() { return mood; } public void setMood(String mood) { this.mood = mood; } public String getReflection() { return reflection; } public void setReflection(String reflection) { this.reflection = reflection; } public Integer getEnergyLevel() { return energyLevel; } public void setEnergyLevel(Integer energyLevel) { this.energyLevel = energyLevel; } public String getRecommendedPractice() { return recommendedPractice; } public void setRecommendedPractice(String recommendedPractice) { this.recommendedPractice = recommendedPractice; } public Instant getCreatedAt() { return createdAt; } public void setCreatedAt(Instant createdAt) { this.createdAt = createdAt; } }
